body:
This is a testcase while investigating another bug that happened to trigger an assert, so I'm leaving it here for curiosity (originally trying to investigate carry signals being optimised more than they should, but then trying to force optimisation by removing `(*abc9_carry*)` and leaving an obvious optimisation in the LUT inits).

```verilog

(* abc9_box, whitebox *)
module MISTRAL_ALUT_ARITH(input A, B, C, D0, D1, input CI, output SO, output CO);

parameter LUT0 = 16'h0000;
parameter LUT1 = 16'h0000;

specify
    (A  => SO) = 1342;
    (B  => SO) = 1323;
    (C  => SO) = 927;
    (D0 => SO) = 887;
    (D1 => SO) = 785;
    (CI => SO) = 368;

    (A  => CO) = 1082;
    (B  => CO) = 1062;
    (C  => CO) = 813;
    (D0 => CO) = 866;
    (D1 => CO) = 1198;
    (CI => CO) = 36; // Divided by 2 to account for there being two ALUT_ARITHs in an ALM)
endspecify

wire q0, q1;

assign q0 = LUT0 >> {D0, C, B, A};
assign q1 = LUT1 >> {D1, C, B, A};

assign {CO, SO} = q0 + !q1 + CI;

endmodule

module top(
	input [2:0] a, b,
	output [2:0] q,
	output soft_co
);

	wire [1:0] c;
	MISTRAL_ALUT_ARITH #(.LUT0(16'hAAAA), .LUT1(16'hC3C3)) i0 (.A(a[0]), .B(b[0]), .C(1'b0), .D0(1'b1), .D1(1'b1), .CI(1'b0), .SO(q[0]), .CO(c[0]));
	MISTRAL_ALUT_ARITH #(.LUT0(16'hAAAA), .LUT1(16'hC3C3)) i1 (.A(a[1]), .B(b[1]), .C(1'b0), .D0(1'b1), .D1(1'b1), .CI(c[0]), .SO(q[1]), .CO(c[1]));
	MISTRAL_ALUT_ARITH #(.LUT0(16'h0000), .LUT1(16'h0000)) i2 (.A(a[2]), .B(b[2]), .C(1'b0), .D0(1'b1), .D1(1'b1), .CI(c[1]), .SO(q[2]), .CO());

	assign soft_co = (a[1] && b[1]) || ((q[1] ^ a[1] ^ b[1]) && (a[1] || b[1]));

endmodule
```

```
yosys -p "read_verilog -specify abc9_carry_mcve.v; prep -top top; techmap; abc9 -lut 4; clean; show"
```

